(window.webpackJsonp=window.webpackJsonp||[]).push([[160],{787:function(n,r){n.exports="\x3c!--\r\ntitle: 06-文件操作\r\nsort:\r\n--\x3e \r\n\r\n> 奇妙的文件管理\r\n\r\n## 文件搜索\r\n\r\n`locate [name]` \r\n\r\n> 搜寻所有含有name的路径\r\n>\r\n> 如找不到此命令,安装`mlocate or slocate`\r\n>\r\n> 新安装需要更新数据库`updatedb`\r\n\r\n`find [path] -[option] [keyword]`\r\n\r\n> 与`wc`连用\r\n>\r\n> `find ~ -type d | wc -l`\r\n>\r\n> 测试条件\r\n>\r\n> `find ~ -type f -name \"*.png\" -size +1M`\r\n>\r\n> 批量删除\r\n>\r\n> `find ~ -type f -name \"nohup.out\" -print`\r\n>\r\n> `find ~ -type f -name \"nohup.out\" -delete`\r\n\r\n### 调用命令\r\n\r\n`-exec`\r\n\r\n> `find ~ -type f -exec ls -l '{}' ';'`\r\n>\r\n> {}: 当前路径名 ; 命令的结束 \r\n>\r\n> `find ~ -type f -ok ls -l '{}' ';'`\r\n>\r\n> 每次运行都会询问\r\n\r\n`xargs`\r\n\r\n> `find ~ | xargs ls -l`\r\n>\r\n> 与上相同\r\n\r\n## 训练\r\n\r\n```bash\r\nmkdir -p dir-{00{1..9},0{10..99},100}\r\ntouch dir-{00{1..9},0{10..99},100}/file-{A..Z}\r\n```\r\n\r\n"}}]);